

export class VideoRecorder {
    private mediaRecorder: MediaRecorder | null = null;
    private chunks: Blob[] = [];
    private canvas: HTMLCanvasElement;
    private stream: MediaStream | null = null;

    // Config
    private readonly targetWidth = 3840;
    private readonly targetHeight = 2160;

    constructor(canvas: HTMLCanvasElement) {
        this.canvas = canvas;
    }

    public isSupported(): boolean {
        return !!(window.MediaRecorder && this.canvas.captureStream);
    }

    public async startRecording(manualFrame = false, fps = 60) {
        if (!this.isSupported()) throw new Error("MediaRecorder API not supported");

        this.chunks = [];

        // Create stream (0 fps for manual, or requested fps for automatic)
        // If manual, we use 0 to stop auto-capture.
        this.stream = this.canvas.captureStream(manualFrame ? 0 : fps);

        // Max bitrate for high quality (e.g. 50Mbps)
        const options: MediaRecorderOptions = {
            mimeType: this.getSupportedMimeType(),
            videoBitsPerSecond: 100 * 1000 * 1000 // 100 Mbps for 4K
        };

        try {
            this.mediaRecorder = new MediaRecorder(this.stream, options);
        } catch (e) {
            console.warn("Failed to create MediaRecorder with ideal options, trying fallback", e);
            // Try fallback options (lower bitrate or default codec)
            try {
                this.mediaRecorder = new MediaRecorder(this.stream, {
                    videoBitsPerSecond: 25 * 1000 * 1000 // 25 Mbps fallback
                });
            } catch (e2) {
                console.warn("Fallback failed, using defaults (Low Quality warning)", e2);
                alert("Warning: Could not configure High Quality recording. Falling back to browser default (resolution might be poor).");
                this.mediaRecorder = new MediaRecorder(this.stream);
            }
        }

        this.mediaRecorder.ondataavailable = (e) => {
            if (e.data && e.data.size > 0) {
                this.chunks.push(e.data);
            }
        };

        this.mediaRecorder.start();
        console.log("Recorder started", manualFrame ? "(Manual Mode)" : "(Auto Mode)");
    }

    public captureFrame() {
        if (this.stream) {
            const track = this.stream.getVideoTracks()[0];
            // @ts-ignore - requestFrame is standard in CanvasCaptureMediaStreamTrack but TS might miss it
            if (track.requestFrame) {
                // @ts-ignore
                track.requestFrame();
            } else {
                // Fallback: This might rely on auto-capture if requestFrame is missing (unlikely in Chrome)
                console.warn("requestFrame not supported on track");
            }
        }
    }

    public stopRecordingAndDownload(filename: string = "gtoc_movie.webm") {
        return new Promise<void>((resolve) => {
            if (!this.mediaRecorder) return resolve();

            // Safety timeout: If browser doesn't fire onstop within 3s, force resolve to unblock UI
            const safetyTimer = setTimeout(() => {
                console.warn("MediaRecorder onstop timeout - forcing cleanup");
                resolve();
            }, 3000);

            this.mediaRecorder.onstop = () => {
                clearTimeout(safetyTimer);
                const mime = this.mediaRecorder?.mimeType || 'video/webm';
                const blob = new Blob(this.chunks, { type: mime });

                // Determine extension
                let ext = 'webm';
                if (mime.includes("mp4")) ext = "mp4";
                else if (mime.includes("matroska")) ext = "mkv";

                const finalFilename = filename.replace(/\.[^/.]+$/, "") + "." + ext;

                // Native download
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.style.display = 'none';
                a.href = url;
                a.download = finalFilename;
                document.body.appendChild(a);
                a.click();
                setTimeout(() => {
                    document.body.removeChild(a);
                    window.URL.revokeObjectURL(url);
                }, 100);

                this.stream?.getTracks().forEach(track => track.stop());
                this.stream = null;
                this.mediaRecorder = null;
                console.log("Recorder stopped, saved", finalFilename);
                resolve();
            };

            if (this.mediaRecorder.state !== 'inactive') {
                this.mediaRecorder.stop();
            } else {
                clearTimeout(safetyTimer);
                resolve();
            }
        });
    }

    private getSupportedMimeType(): string {
        const types = [
            'video/mp4', // Modern Chrome/Edge support this
            'video/mp4;codecs=avc1',
            'video/mp4;codecs=h264',
            'video/x-matroska;codecs=avc1', // MKV/H.264 often compatible
            'video/webm;codecs=vp9',
            'video/webm;codecs=vp8',
            'video/webm'
        ];
        for (const t of types) {
            if (MediaRecorder.isTypeSupported(t)) return t;
        }
        return '';
    }
}
